import { describe, it, expect } from "vitest";
import { runScenario } from "./cli.js";

describe("claim-office CLI — runScenario", () => {
  // --- Valid scenarios, simple → complex ---

  it.todo("returns { results: [] } for a scenario with no steps");

  it.todo(
    "returns premium 59 for a single amulet quote (customer yearsWithMHPCO 5, first contract): 60 base - 12 loyalty + 6 first-insurance + 5 fee",
  );

  it.todo(
    "returns payout 100 and remainingCap 1100 for a claim of amount 200 on an amulet quote (200 - 100 deductible; cap 2*600 - 100)",
  );

  it.todo(
    "returns results in the same order and length as steps for a quote followed by a claim (quote premium then claim payout/remainingCap)",
  );

  it.todo(
    "applies the follow-up discount to the second quote of the same customer (first quote previousContracts 0, second quote previousContracts 1: first-insurance + 15% follow-up)",
  );

  it.todo(
    "draws down a shared cap across two successive claims on the same policy: first sword claim 1500 → payout 1400 remainingCap 600, second sword claim 1500 → payout 600 remainingCap 0",
  );

  // --- Error cases ---

  it.todo("throws when a quote includes an item with an unknown type");

  it.todo(
    "throws when a claim references a damage entry whose itemType is not part of the referenced policy",
  );

  it.todo("throws when a claim contains a damage entry with a negative amount");

  it.todo(
    "throws when a claim's damages contain more entries of a type than the policy covers (e.g. two sword damages but only one sword insured)",
  );
});
